pub fn findLower(cp: u21) ?u21 {
    var lo: usize = 0;
    var hi: usize = downcase_table.len;
    while (lo < hi) {
        const mid = lo + (hi - lo) / 2;
        if (downcase_table[mid].from == cp) return downcase_table[mid].to;
        if (downcase_table[mid].from < cp) { lo = mid + 1; } else { hi = mid; }
    }
    return null;
}

